export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "16:45。她們坐了幾分鐘。誰都沒有先說正事。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後水瀨佳乃開口了。不是問名字。不是問背景。她說了一句讓澪一瞬間繃緊的話。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.MinaseYoshino, character: "水瀨佳乃", dialogue: "不要給我看照片。妳先說，他畫的海裡有什麼。", background: Background.Chapter_10_Ch10_Act8_S0, portrait: Portrait.MinaseYoshino_Guarded },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯⋯⋯她在測我。她在反過來測我。她不讓我拿照片出來。她要我先用嘴巴說。說錯了就結束。說對了才往下走。", background: Background.Chapter_10_Ch10_Act8_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪的手在桌面下握了一下。又鬆開。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯不對。不是測。或者不全是測。她不是在套我的話。她是不想把她女兒的圖再拿給不相關的人看。她已經把那張紙拿給太多人了。警察。學校。研究單位。每一個人都看了。每一個人都給了一個不是答案的答案。她不想再浪費一次。", background: Background.Chapter_10_Ch10_Act8_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯她要我先證明。證明我也是。證明我弟弟也畫過。證明我不是來消費她女兒的圖的。", background: Background.Chapter_10_Ch10_Act8_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪看著她。水瀨佳乃的臉沒有表情。不是冷。是已經把表情用完了。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "海面不像水。", background: Background.Chapter_10_Ch10_Act8_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "像黑的。沒有反光的那種黑。不是深藍。不是暗。是黑。像你把臉湊到水面，水面不映你的臉。", background: Background.Chapter_10_Ch10_Act8_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她停了一下。水瀨佳乃沒有打斷。也沒有點頭。她在聽。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "月亮是倒過來的。", background: Background.Chapter_10_Ch10_Act8_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "水瀨佳乃的眼睛動了一下。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "海上有七條線。不是波浪。是線。直的。從海面延伸出去。像被什麼東西從底下頂上來的痕跡。", background: Background.Chapter_10_Ch10_Act8_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她說到「七條線」的時候，水瀨佳乃的表情變了。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯她變了。不是驚訝。是確認。她聽過這些。她見過這些。她女兒畫的也是這些。倒過來的月亮。七條線。她沒有問我幾條。她等我說完。她聽到「七」的時候，臉上那層防備鬆了一點。只有一點。", background: Background.Chapter_10_Ch10_Act8_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪還有一句沒說。她猶豫了一下。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "悠真說過一句話。他說「那邊會亮」。", background: Background.Chapter_10_Ch10_Act8_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.MinaseYoshino, character: "水瀨佳乃", dialogue: "⋯⋯", background: Background.Chapter_10_Ch10_Act8_S0, portrait: Portrait.MinaseYoshino_Shocked },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我以前以為那是夢話。他睡著的時候說的。我沒有追問。我應該追問的。", background: Background.Chapter_10_Ch10_Act8_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "水瀨佳乃沒有回應那句「應該追問的」。她低下頭。看了一眼自己的包。然後她做了澪沒有預期的動作。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把包拉過來。打開。從裡面拿出一張紙。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是文件。不是列印清楚的報告。是一張影印紙。A4。對折過。又對折過。折痕很深。紙面有點皺。右下角有一圈淡褐色的漬。咖啡。像有人邊喝咖啡邊翻這張紙。翻過太多次了。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯⋯⋯", background: Background.Chapter_10_Ch10_Act8_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "水瀨佳乃把紙攤開。推到桌面中間。沒有翻面。正面朝上。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪低頭看。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "黑色海。倒過來的月亮。七條線。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是悠真畫的。筆觸不同。線條更圓潤一點。像年紀更小的孩子畫的。海面也是黑的。沒有反光。月亮也是倒的。七條線也在。一模一樣的構圖。一模一樣的東西出現在一個她不認識的孩子筆下。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯一樣的。完全一樣的。不是相似。是同一個圖。同一片海。同一個倒月。同樣七條線。悠真畫過。這個孩子也畫過。他們不認識彼此。他們不可能看過對方的畫。可是他們畫了同一片海。", background: Background.Chapter_10_Ch10_Act8_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的手放在膝蓋上。沒有去碰那張紙。紙面上的咖啡漬在下午的光裡看起來像一塊舊地圖的水印。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.MinaseYoshino, character: "水瀨佳乃", dialogue: "警察說這是壓力。", background: Background.Chapter_10_Ch10_Act8_S0, portrait: Portrait.MinaseYoshino_Sad },
    { characterId: CharacterId.MinaseYoshino, character: "水瀨佳乃", dialogue: "學校說這是青春期。", background: Background.Chapter_10_Ch10_Act8_S0, portrait: Portrait.MinaseYoshino_Sad },
    { characterId: CharacterId.MinaseYoshino, character: "水瀨佳乃", dialogue: "研究那邊說這是睡眠品質低下。", background: Background.Chapter_10_Ch10_Act8_S0, portrait: Portrait.MinaseYoshino_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她說這三句的時候語氣是平的。不是冷漠。是已經說過太多次。每說一次就像從同一個地方再刮一層。刮到現在什麼都剩不多了。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.MinaseYoshino, character: "水瀨佳乃", dialogue: "可是我女兒不認識妳弟弟。她不可能和他做同一個壓力夢。", background: Background.Chapter_10_Ch10_Act8_S0, portrait: Portrait.MinaseYoshino_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這句話落在桌面上。很輕。但澪覺得整個休息區都安靜了一瞬。當然沒有。販賣機還在嗡。棋子還在響。小孩還在翻繪本。世界沒有停。只有這張桌子停了。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "悠真也畫了。", background: Background.Chapter_10_Ch10_Act8_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "三個字。她說得很輕。像怕太大聲會把那張影印紙上的咖啡漬震掉。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "水瀨佳乃沒有鬆一口氣。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯她沒有放鬆。她更難過了。她的肩膀往下沉了一點。嘴角的線更緊了。因為這代表不是只有她。不是只有葵。又一個家庭。又一個孩子。又一個掉進同一個洞裡的人。她等了四十一天。她以為也許只有她。也許真的是壓力。也許真的是青春期。也許她瘋了。可是現在坐在她對面的人說「悠真也畫了」。她沒有被證明是對的。她被證明不是唯一一個。", background: Background.Chapter_10_Ch10_Act8_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "而那比被證明是對的更難承受。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "水瀨佳乃把視線從澪臉上移開。落在那張影印紙上。看了很久。像在看一個她已經看了四十一天的東西，試圖從裡面再讀出任何還沒被讀完的字。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.MinaseYoshino, character: "水瀨佳乃", dialogue: "那他有沒有說過，海的另一邊是亮的？", background: Background.Chapter_10_Ch10_Act8_S0, portrait: Portrait.MinaseYoshino_Sad },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯⋯⋯海的另一邊。是亮的。那邊會亮。悠真說過。那邊會亮。她女兒也說過嗎。她也在問同一件事。海的另一邊。亮。悠真和葵。兩個不認識的孩子。畫了同一片黑海。說了同一句話。", background: Background.Chapter_10_Ch10_Act8_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪沒有回答。不是不想回答。是喉嚨堵住了。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她低頭看著那張影印紙。皺摺。咖啡漬。折痕。被太多人翻過。被太多人還回去。被太多人說「這只是壓力」。被太多人說「這只是青春期」。被太多人說「這只是睡眠品質低下」。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後被一個母親折好。放回包裡。帶回家。第二天再拿出來。再折好。再帶去下一個地方。四十一天。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯悠真的房間。我以為那是終點。我以為翻完他的東西、找到他的帳號、看見他畫的黑色海，就到了盡頭。就到底了。就是最深的地方。", background: Background.Chapter_10_Ch10_Act8_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯不是。", background: Background.Chapter_10_Ch10_Act8_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯悠真的房間不是終點。那只是第一扇門。門的後面是這片海。這片黑色的、沒有反光的、倒著月亮的海。而這片海不只有悠真一個人看見。葵也看見了。也許還有別人。也許有很多別人。他們都畫了同一張圖。他們都沒有回來。", background: Background.Chapter_10_Ch10_Act8_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著那張紙。黑色海。倒月。七條線。咖啡漬。折痕。一個十四歲少女的筆觸。一個討厭游泳、總在美術課畫魚、會把冰棒棍收集起來寫日期的女孩，畫出來的東西。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她畫的魚是日常。她畫的黑色海不是。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "販賣機響了一聲。有人買了第三罐咖啡。棋盤那邊的老人收了一顆子。兒童閱讀角的小孩被媽媽抱起來，準備回家。下午的光從窗戶斜進來，照在那張影印紙上。咖啡漬在光裡看起來像一塊很舊的水印。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "水瀨佳乃沒有把紙收回去。她讓它攤在桌上。等著。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪看著那張紙。看著那片黑。看著那個倒過來的月亮。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她忽然明白了一件事。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "悠真的房間不是終點。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那只是這片黑色海的第一扇門。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "而門的後面，還有很多扇。每一扇門後面都坐著一個人。都等著一個沒有回來的孩子。都拿著一張被太多人翻過、被太多人說「這只是壓力」的紙。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她還沒有找到悠真。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但她找到了另一個也沒有回家的孩子。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "而那個孩子的母親，正坐在她對面。等她承認一件她已經知道、卻還沒有說出口的事。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.MinaseYoshino, character: "水瀨佳乃", dialogue: "妳弟弟也畫了這個，對不對？", background: Background.Chapter_10_Ch10_Act8_S0, portrait: Portrait.MinaseYoshino_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪沒有點頭。也沒有搖頭。她看著那張皺掉的影印紙。看著上面那片黑。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "17:15。區民中心的燈還沒有亮。下午的光正在變薄。販賣機的嗡聲填著安靜。藍色傘靠在桌腳。兩個女人坐在一張桌子兩邊。中間攤著一張被太多人看過的紙。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "紙上也是黑色的海。海上也是倒過來的月亮。", background: Background.Chapter_10_Ch10_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "而澪終於知道，她不是唯一一個被逼到相信夢的人。", background: Background.Chapter_10_Ch10_Act8_S0 },
];
